import{c as d,Z as s,Q as p,j as l,g as t,n as o,o as a,m as r,av as h}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"Install & set up the MCP server","description":"Install @muhaven/mcp, paste your dashboard-minted Scoped key when prompted, and verify the broker end-to-end.","frontmatter":{"title":"Install & set up the MCP server","description":"Install @muhaven/mcp, paste your dashboard-minted Scoped key when prompted, and verify the broker end-to-end."},"headers":[],"relativePath":"guide/mcp/install.md","filePath":"guide/mcp/install.md","lastUpdated":1780218602000}'),c={name:"guide/mcp/install.md"};function u(g,e,m,k,y,b){const n=s("TaskMeta"),i=s("ExpectedResult");return p(),l("div",null,[e[1]||(e[1]=t("h1",{id:"install-set-up-the-mcp-server",tabindex:"-1"},[o("Install & set up the MCP server "),t("a",{class:"header-anchor",href:"#install-set-up-the-mcp-server","aria-label":'Permalink to "Install & set up the MCP server"'},"​")],-1)),a(n,{time:"~5 min",role:"Investor",needs:"Node 20+, a Scoped session key from M1, an MCP-aware host (Claude Code/Desktop/Cursor)"}),e[2]||(e[2]=r('<blockquote><p><strong>What you&#39;ll do:</strong> install the <code>@muhaven/mcp</code> terminal server, <strong>paste the Scoped session key you minted in <a href="/guide/mcp/arm-scoped">M1</a></strong> when <code>setup</code> prompts, verify the broker, then ask <strong>your own LLM</strong> &quot;what&#39;s my portfolio?&quot; and watch it call a MuHaven tool.</p></blockquote><p>This is the install step of the <strong>MCP track</strong> — driving your confidential MuHaven portfolio from <strong>your own LLM host</strong> (Claude Code, Claude Desktop, Cursor) instead of the in-dashboard HavenBot copilot. For the deep reference, see <a href="/mcp/install">/mcp/install</a> and <a href="/mcp/troubleshooting">/mcp/troubleshooting</a>.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><ul><li><strong>Node 20 or later.</strong></li><li>A <strong>Scoped session key</strong> copied from the dashboard — do <a href="/guide/mcp/arm-scoped">M1 · Arm Scoped autonomy</a> first. (You <em>can</em> skip it and let <code>setup</code> mint a read/propose-only key, but then trades fall back to a dashboard deep-link.)</li><li>An <strong>MCP-aware host</strong>: Claude Code, Claude Desktop, or Cursor.</li></ul></div><h2 id="step-1-—-install-globally-and-verify-the-binaries" tabindex="-1">Step 1 — Install globally and verify the binaries <a class="header-anchor" href="#step-1-—-install-globally-and-verify-the-binaries" aria-label="Permalink to &quot;Step 1 — Install globally and verify the binaries&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @muhaven/mcp@0.6.2</span></span></code></pre></div><p>This installs two binaries — <code>muhaven-broker</code> (the long-lived per-user daemon) and <code>muhaven-mcp</code> (the STDIO subprocess your host spawns). Confirm they&#39;re on your PATH:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-mcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div><p><strong>Expected:</strong> each prints usage text. If you see <code>command not found</code>, your npm global bin isn&#39;t on PATH — see Troubleshooting below.</p><h2 id="step-2-—-set-up-and-paste-your-scoped-key-when-prompted" tabindex="-1">Step 2 — Set up, and paste your Scoped key when prompted <a class="header-anchor" href="#step-2-—-set-up-and-paste-your-scoped-key-when-prompted" aria-label="Permalink to &quot;Step 2 — Set up, and paste your Scoped key when prompted&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --register</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-code</span></span></code></pre></div><p>As it runs, <code>setup</code> asks:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Do you have a session key from the dashboard? [Y/n]</span></span></code></pre></div><p>Answer <strong><code>Y</code></strong>, then <strong>paste the raw Scoped key you copied in <a href="/guide/mcp/arm-scoped">M1</a></strong> at the <code>Paste the session key:</code> prompt (your input is hidden). <code>setup</code> then, in order —</p><ol><li><strong>Applies env defaults</strong> (<code>MUHAVEN_BACKEND_URL</code>, <code>MUHAVEN_DASHBOARD_URL</code>; and <code>MUHAVEN_KEYRING=file</code> on Windows/WSL2/SSH).</li><li><strong>Brings the broker up on your Scoped key</strong> — the daemon now signs trades with the signer your dashboard session authorized.</li><li><strong>Opens your browser</strong> to <code>muhaven.app/link?code=…</code> for a <strong>device-code passkey approval</strong> — review the requesting client (name, scopes, fingerprint) and approve with your passkey.</li><li><strong>Registers the host</strong> (<code>claude mcp add-json muhaven …</code>).</li><li><strong>Prints a closing summary</strong> with the daemon PID + endpoint + the stop command.</li></ol><div class="tip custom-block"><p class="custom-block-title">No Scoped key yet?</p><p>If you press <strong><code>n</code></strong> (or you&#39;re piping/CI with no key), <code>setup</code> mints a fresh <strong>ephemeral</strong> key that can read and <em>propose</em> — your LLM&#39;s buys/sells then return a dashboard deep-link you approve by hand. To upgrade to autonomous later, mint a Scoped session (<a href="/guide/mcp/arm-scoped">M1</a>) and run the one-paste <strong><code>muhaven-broker update --session …</code></strong> command from the reveal modal.</p></div><h2 id="step-3-—-verify-the-broker-with-doctor" tabindex="-1">Step 3 — Verify the broker with <code>doctor</code> <a class="header-anchor" href="#step-3-—-verify-the-broker-with-doctor" aria-label="Permalink to &quot;Step 3 — Verify the broker with `doctor`&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">muhaven-broker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p><strong>Expected output</strong> includes:</p><ul><li>the broker <strong>signer address</strong> — <code>0x…</code>. This should match the <strong>session signer</strong> shown on your dashboard policy page (proof your Scoped key is the one installed).</li><li>the <strong>JWT scopes</strong> — <code>mcp.read.*</code> plus <code>mcp.propose.*</code></li><li>the <strong>keystore location</strong> (OS keychain, or <code>~/.muhaven/jwt.json</code> with the file keyring)</li><li>the <strong>broker socket path</strong></li></ul><h2 id="step-4-—-restart-your-host-and-ask-it-to-read-your-portfolio" tabindex="-1">Step 4 — Restart your host and ask it to read your portfolio <a class="header-anchor" href="#step-4-—-restart-your-host-and-ask-it-to-read-your-portfolio" aria-label="Permalink to &quot;Step 4 — Restart your host and ask it to read your portfolio&quot;">​</a></h2><p>Restart your MCP host so it picks up the newly registered <code>muhaven</code> server, then prompt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; What does my muhaven portfolio look like?</span></span></code></pre></div><p><strong>Expected:</strong> your LLM makes a MuHaven <strong>read</strong> tool call and returns your aggregate state (aggregates and encrypted handles — never your cleartext balances).</p><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',25)),a(i,null,{default:h(()=>[...e[0]||(e[0]=[o(" Your host lists the ",-1),t("strong",null,"muhaven",-1),o(" MCP server; ",-1),t("code",null,"doctor",-1),o(" shows a signer that matches your dashboard Scoped session; and asking ",-1),t("em",null,`"what's my portfolio?"`,-1),o(" returns your aggregate state — no passkey prompt, no transaction (reads are free). ",-1)])]),_:1}),e[3]||(e[3]=r('<h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td><code>muhaven-broker: command not found</code></td><td>Your npm global bin isn&#39;t on PATH. Add npm&#39;s global bin dir (find it with <code>npm bin -g</code>) to your shell PATH, then reopen the terminal.</td></tr><tr><td>The pasted key was rejected</td><td><code>setup</code> expects the <strong>raw <code>0x…</code> 64-hex key</strong> (66 chars), not the <code>muhaven-broker update …</code> command. Re-copy with <strong>Copy raw key</strong> in the reveal modal (<a href="/guide/mcp/arm-scoped">M1</a>).</td></tr><tr><td>Browser didn&#39;t open, or the login link expired</td><td>Re-run <code>muhaven-broker setup</code>. The login JWT is ~1 hour — re-running re-opens <code>muhaven.app/link</code>.</td></tr><tr><td><code>doctor</code> shows no JWT / an auth error</td><td>The daemon is up but not logged in — run <code>muhaven-broker login</code> and approve with your passkey.</td></tr><tr><td><code>doctor</code> signer ≠ your dashboard session</td><td>The broker came up on an ephemeral key. Mint a Scoped session (<a href="/guide/mcp/arm-scoped">M1</a>) and run the modal&#39;s <code>muhaven-broker update --session …</code> command.</td></tr><tr><td>Host doesn&#39;t list the <code>muhaven</code> server / its 25 tools</td><td>Restart the host, and check the host&#39;s MCP config (<code>claude mcp list</code> for Claude Code, or the host&#39;s MCP settings).</td></tr><tr><td>Windows / WSL2 / SSH keyring error</td><td>The OS keychain is unavailable on that surface — <code>export MUHAVEN_KEYRING=file</code> (a 0600-mode file at <code>~/.muhaven/jwt.json</code>), then re-run setup.</td></tr></tbody></table><p>For deeper coverage see the full <a href="/mcp/install">MCP install reference</a> and <a href="/mcp/troubleshooting">MCP troubleshooting</a>.</p><p>→ Next: <a href="/guide/mcp/reads">Read your portfolio via MCP</a></p>',4))])}const C=d(c,[["render",u]]);export{f as __pageData,C as default};
